package com.intellij.ui.webview.impl

import com.intellij.ui.webview.api.WebViewAssetPath
import com.intellij.ui.webview.api.WebViewAssetProviderResult
import com.intellij.ui.webview.api.WebViewIconSet

/**
 * Serves raw SVG/PNG icon resources for URLs generated by the TypeScript `IconSet` helper.
 *
 * The resolver receives paths without a leading slash and handles only this reserved route:
 * `__ij-icons/<icon-set-id>/<light|dark>/<resource-path>`.
 * Browser code creates the matching relative URL as `./__ij-icons/...`.
 *
 * `<resource-path>` is a classpath-relative resource name resolved from the registered icon-set owner classloader,
 * not a repository or filesystem path. Supported resources are `.svg` and `.png`; leading slashes, URI schemes,
 * `.`, `..`, and empty path segments are rejected. Malformed route/flavor/path requests return 403, while valid
 * requests for an unknown icon set or a missing resource return 404.
 *
 * Dark requests first try a sibling `*_dark.svg` or `*_dark.png` resource and then fall back to the original path.
 */
internal class WebViewIconSetAssetProvider(
  private val iconSets: Map<String, WebViewIconSet>,
) {
  fun resolve(requestPath: String): WebViewAssetProviderResult? {
    val path = requestPath.trimStart('/')
    if (path == REQUEST_PREFIX) {
      return WebViewAssetProviderResult.Forbidden("Malformed WebView icon asset path: $path")
    }

    val routePath = path.removePrefix("$REQUEST_PREFIX/")
    if (routePath == path) return null

    // Keep the resource path intact: it can contain nested classpath segments after the flavor.
    val parts = routePath.split('/', limit = 3)
    if (parts.size != 3) {
      return WebViewAssetProviderResult.Forbidden("Malformed WebView icon asset path: $path")
    }

    val iconSetId = parts[0]
    val flavor = WebViewIconFlavor.fromPathSegment(parts[1])
    val resourcePath = parseResourcePath(parts[2]) ?: return WebViewAssetProviderResult.Forbidden("Invalid WebView icon resource path: ${parts[2]}")

    if (!WebViewIconSet.isValidId(iconSetId)) {
      return WebViewAssetProviderResult.Forbidden("Invalid WebView icon set id: $iconSetId")
    }
    if (flavor == null) {
      return WebViewAssetProviderResult.Forbidden("Invalid WebView icon flavor: ${parts[1]}")
    }

    val iconSet = iconSets[iconSetId]
                  ?: return WebViewAssetProviderResult.NotFound("WebView icon set not found: $iconSetId")
    return resolveIcon(iconSet, flavor, resourcePath)
           ?: WebViewAssetProviderResult.NotFound("WebView icon resource not found: ${resourcePath.path}")
  }

  private fun parseResourcePath(path: String): WebViewAssetPath? {
    if (path.startsWith('/') || path.split('/').any { it.isEmpty() || it == "." || it == ".." }) {
      return null
    }

    val resourcePath = try {
      WebViewAssetPath.of(path)
    }
    catch (_: IllegalArgumentException) {
      return null
    }
    return if (isSupportedIconPath(resourcePath.path)) resourcePath else null
  }

  private fun resolveIcon(iconSet: WebViewIconSet, flavor: WebViewIconFlavor, resourcePath: WebViewAssetPath): WebViewAssetProviderResult.Content? {
    if (flavor == WebViewIconFlavor.DARK) {
      resolveIconResource(iconSet, darkResourcePath(resourcePath))?.let { return it }
    }
    return resolveIconResource(iconSet, resourcePath)
  }

  private fun resolveIconResource(iconSet: WebViewIconSet, resourcePath: WebViewAssetPath): WebViewAssetProviderResult.Content? {
    val bytes = iconSet.classLoader.getResourceAsStream(resourcePath.path)?.use { it.readBytes() } ?: return null
    return WebViewAssetProviderResult.Content.of(
      contentType = webViewAssetContentType(resourcePath.path),
      bytes = bytes,
      headers = mapOf("Cache-Control" to "no-cache"),
    )
  }

  private fun darkResourcePath(resourcePath: WebViewAssetPath): WebViewAssetPath {
    val path = resourcePath.path
    val extensionStart = path.lastIndexOf('.')
    return WebViewAssetPath.of("${path.substring(0, extensionStart)}_dark${path.substring(extensionStart)}")
  }

  private fun isSupportedIconPath(path: String): Boolean {
    return path.endsWith(".svg") || path.endsWith(".png")
  }

  companion object {
    private const val REQUEST_PREFIX = "__ij-icons"
  }
}

private enum class WebViewIconFlavor(val pathSegment: String) {
  LIGHT("light"),
  DARK("dark"),
  ;

  companion object {
    fun fromPathSegment(pathSegment: String): WebViewIconFlavor? {
      return entries.firstOrNull { it.pathSegment == pathSegment }
    }
  }
}
